        '{\"0\":{\"correct_answer_index\":\"Rekursi\",\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003eDalam \\u003cstrong\\u003epemrograman imperatif\\u003c/strong\\u003e, kita sering menggunakan \\u003cstrong\\u003eloop\\u003c/strong\\u003e seperti for atau while untuk mengulang suatu proses. Namun, dalam \\u003cstrong\\u003enotasi fungsional\\u003c/strong\\u003e, kita tidak menggunakan loop melainkan \\u003cstrong\\u003erekursi\\u003c/strong\\u003e.\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":23,\"type\":\"short_answer\",\"user_answer_index\":\"loop\"},\"1\":{\"correct_answer_id\":62,\"correct_answer_index\":1,\"exp_gained\":10,\"feedback\":\"\\u003cul\\u003e\\u003cli\\u003e\\u003cstrong\\u003eA (Judul Fungsi)\\u003c/strong\\u003e → Berisi nama dan parameter fungsi.\\u003c/li\\u003e\\u003cli\\u003e\\u003cstrong\\u003eB (Definisi \\u0026amp; Spesifikasi)\\u003c/strong\\u003e → Menjelaskan domain, range, dan deskripsi fungsi.\\u003c/li\\u003e\\u003cli\\u003e\\u003cstrong\\u003eC (Realisasi)\\u003c/strong\\u003e → Berisi implementasi atau cara kerja fungsi.\\u003c/li\\u003e\\u003c/ul\\u003e\\u003cp\\u003e\\u003cstrong\\u003eD (Aplikasi)\\u003c/strong\\u003e → Menunjukkan penggunaan fungsi dalam ekspresi nyata.\\u003c/p\\u003e\\u003cp\\u003e\\u003cbr\\u003e\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":24,\"type\":\"multiple_choice\",\"user_answer_id\":62,\"user_answer_index\":1}}',
