        '{\"0\":{\"correct_answer\":\"true\",\"correct_answer_index\":0,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Operator mod menghitung sisa pembagian, sehingga 5 mod 2 menghasilkan 1, yang \\u003cstrong\\u003ebenar\\u003c/strong\\u003e\\u003c/p\\u003e\",\"point_gained\":5,\"question_id\":48,\"type\":\"true_false\",\"user_answer\":\"True\",\"user_answer_index\":0},\"1\":{\"correct_answer_id\":117,\"correct_answer_index\":1,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Bentuk prefix meletakkan operator sebelum operand, sehingga (* (+ 3 4) 5) adalah jawaban yang benar.\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":49,\"type\":\"multiple_choice\",\"user_answer_id\":117,\"user_answer_index\":1},\"2\":{\"correct_answer_index\":\"2\",\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Operator div melakukan pembagian bulat, sehingga 8 div 3 menghasilkan 2.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":50,\"type\":\"short_answer\",\"user_answer_index\":\"C\"},\"3\":{\"correct_answer_id\":[121,123,124],\"correct_answer_index\":[0,2,3],\"exp_gained\":0,\"feedback\":\"\\u003cul\\u003e\\u003cli\\u003e4 + 3 = 7 benar\\u003c/li\\u003e\\u003cli\\u003e6 \\u0026gt; 9 salah\\u003c/li\\u003e\\u003cli\\u003e10 mod 2 = 0 benar\\u003c/li\\u003e\\u003cli\\u003e(5 \\u0026gt; 2) and (7 \\u0026gt; 3) benar\\u003c/li\\u003e\\u003c/ul\\u003e\",\"point_gained\":0,\"question_id\":51,\"type\":\"multiple_answer\",\"user_answer_id\":[121,122],\"user_answer_index\":[0,1],\"user_correct_answer_id\":[121]},\"4\":{\"correct_answer\":\"true\",\"correct_answer_index\":0,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e(4 + 2) = 6, lalu 6 * 3 = 18, sehingga hasilnya benar.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":5,\"question_id\":52,\"type\":\"true_false\",\"user_answer\":\"True\",\"user_answer_index\":0},\"5\":{\"correct_answer_index\":\"25\",\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;FX2(5) = 5 * 5 = 25\\u003c/p\\