        '{\"0\":{\"correct_answer_id\":145,\"correct_answer_index\":0,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003eOperator \\u0026gt;= akan mengembalikan True jika nilai di kiri lebih besar atau sama dengan nilai di kanan. Karena a bernilai 5, ekspresi a \\u0026gt;= 5 bernilai True.\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":60,\"type\":\"multiple_choice\",\"user_answer_id\":145,\"user_answer_index\":0},\"1\":{\"correct_answer\":\"false\",\"correct_answer_index\":1,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003eDalam banyak bahasa pemrograman, evaluasi ekspresi kondisional menggunakan \\u003cstrong\\u003eshort-circuiting\\u003c/strong\\u003e, artinya jika satu kondisi sudah terpenuhi, maka kondisi lainnya tidak akan diperiksa.\\u003c/p\\u003e\",\"point_gained\":5,\"question_id\":61,\"type\":\"true_false\",\"user_answer\":\"False\",\"user_answer_index\":1}}',
