        '{\"0\":{\"correct_answer_id\":355,\"correct_answer_index\":0,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e\\u003cstrong\\u003eA. 3\\u003c/strong\\u003e → Benar! FirstElmt(L) mengambil elemen pertama dari list.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eB. 7\\u003c/strong\\u003e → Salah, karena 7 adalah elemen kedua, bukan pertama.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eC. 9\\u003c/strong\\u003e → Salah, karena 9 adalah elemen ketiga.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eD. [3, 7]\\u003c/strong\\u003e → Salah, karena ini bukan satu elemen, melainkan dua.\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":144,\"type\":\"multiple_choice\",\"user_answer_id\":355,\"user_answer_index\":0},\"1\":{\"correct_answer\":\"true\",\"correct_answer_index\":0,\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003eTrue - Tail(L) mengembalikan list tanpa elemen pertama, yaitu [8, 12].\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":145,\"type\":\"true_false\",\"user_answer\":\"False\",\"user_answer_index\":1},\"2\":{\"correct_answer_id\":[360,361],\"correct_answer_index\":[0,1],\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003e\\u003cstrong\\u003eKonso\\u003c/strong\\u003e → Benar! Konso(e, L) menambahkan e di awal list.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eKons•\\u003c/strong\\u003e → Benar! Kons•(L, e) menambahkan e di akhir list.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eTail\\u003c/strong\\u003e → Salah, karena Tail(L) hanya menghapus elemen pertama, bukan menambah.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eFirstElmt\\u003c/strong\\u003e → Salah, karena FirstElmt(L) hanya mengambil elemen pertama, tidak menambahkan elemen.\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":146,\"type\":\"multiple_answer\",\"user_answer_id\":[362,361],\"user_answer_index\":[2,1],\"user_correct_answer_id\":[361]},\"3\":{\"correct_answer_id\":366,\"correct_answer_index\":2,\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003e\\u003cstrong\\u003eA. 2\\u003c/strong\\u003e → Salah, karena 2 adalah elemen pertama.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eB. 4\\u003c/strong\\u003e → Salah, karena 4 bukan elemen terakhir.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eC. 8\\u003c/strong\\u003e → Benar! LastElmt(L) mengambil elemen terakhir dari list.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eD. [6, 8]\\u003c/strong\\u003e → Salah, karena hasilnya harus satu elemen, bukan list baru.\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":147,\"type\":\"multiple_choice\",\"user_answer_id\":365,\"user_answer_index\":1},\"4\":{\"correct_answer\":\"true\",\"correct_answer_index\":0,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e\\u003cstrong\\u003eTrue\\u003c/strong\\u003e → Benar! IsEmpty(L) mengembalikan True jika list kosong.\\u003c/p\\u003e\\u003cp\\u003e\\u003cstrong\\u003eFalse\\u003c/strong\\u003e → Salah, karena list kosong memang menghasilkan True saat diperiksa dengan IsEmpty(L).\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":148,\"type\":\"true_false\",\"user_answer\":\"True\",\"user_answer_index\":0}}',
