        '{\"0\":{\"correct_answer_id\":16,\"correct_answer_index\":1,\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003eParadigma OOP mengorganisir kode ke dalam objek yang memiliki atribut (data) dan metode (fungsi yang dapat dijalankan oleh objek). Hal ini membuat kode lebih terstruktur dan modular.\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":6,\"type\":\"multiple_choice\",\"user_answer_id\":15,\"user_answer_index\":0},\"1\":{\"correct_answer\":\"true\",\"correct_answer_index\":0,\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003eOOP sangat cocok untuk proyek besar karena mendukung konsep modularitas, enkapsulasi, dan pewarisan, yang memudahkan pengelolaan dan pemeliharaan kode dalam skala besar seperti aplikasi web dan game.\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":7,\"type\":\"true_false\",\"user_answer\":\"False\",\"user_answer_index\":1}}',
