        '{\"0\":{\"correct_answer\":\"false\",\"correct_answer_index\":1,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Type bentukan terdiri dari kombinasi beberapa tipe data dasar, bukan hanya satu.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":77,\"type\":\"true_false\",\"user_answer\":\"False\",\"user_answer_index\":1},\"1\":{\"correct_answer_id\":193,\"correct_answer_index\":2,\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Integer, String, dan Boolean adalah tipe data dasar, sedangkan Koordinat (x, y) adalah contoh type bentukan.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":78,\"type\":\"multiple_choice\",\"user_answer_id\":192,\"user_answer_index\":1},\"2\":{\"correct_answer_id\":[195,197],\"correct_answer_index\":[0,2],\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Type bentukan membantu pengorganisasian data dan mempermudah pengeditan kode, tetapi tidak selalu mempercepat eksekusi atau mengurangi ukuran kode secara drastis.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":79,\"type\":\"multiple_answer\",\"user_answer_id\":[195,196],\"user_answer_index\":[0,1],\"user_correct_answer_id\":[195]},\"3\":{\"correct_answer_index\":\"Konstruktor\",\"exp_gained\":15,\"feedback\":\"\\u003cp\\u003eKonstruktor digunakan untuk membuat objek baru dari type bentukan.\\u003c/p\\u003e\",\"point_gained\":15,\"question_id\":80,\"type\":\"short_answer\",\"user_answer_index\":\"Konstruktor\"},\"4\":{\"correct_answer\":\"true\",\"correct_answer_index\":0,\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Titik (0,0) adalah titik awal dalam sistem koordinat kartesian.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":81,\"type\":\"true_false\",\"user_answer\":\"True\",\"user_answer_index\":0},\"5\":{\"correct_answer_id\":202,\"correct_answer_index\":1,\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Selektor digunakan untuk mengambil informasi dari type bentukan yang sudah dibuat.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":82,\"type\":\"multiple_choice\",\"user_answer_id\":201,\"user_answer_index\":0},\"6\":{\"correct_answer_index\":\"\\u003cp\\u003eKonstruktor digunakan untuk membuat objek baru dari type bentukan, sedangkan selektor digunakan untuk mengambil nilai dari objek yang telah dibuat. Misalnya, dalam tipe koordinat (x, y), konstruktor membuat titik baru, sedangkan selektor mengambil nilai x atau y dari titik tersebut.\\u0026nbsp;\\u003c/p\\u003e\",\"exp_gained\":30,\"feedback\":\"\\u003cp\\u003eKonstruktor digunakan untuk membuat objek baru dari type bentukan, sedangkan selektor digunakan untuk mengambil nilai dari objek yang telah dibuat. Misalnya, dalam tipe koordinat (x, y), konstruktor membuat titik baru, sedangkan selektor mengambil nilai x atau y dari titik tersebut.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":30,\"question_id\":83,\"type\":\"essay\",\"user_answer_index\":\"seperti namanya konstruktor digunakan untuk membuat salinan objek baru dari tipe bentukan, namun selektor digunakan untuk mengambil nilai dari objek baru yang telah kita buat tadinya\"},\"7\":{\"correct_answer_index\":\"Nol\",\"exp_gained\":15,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Penyebut pecahan tidak boleh nol karena pembagian dengan nol tidak terdefinisi.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":15,\"question_id\":84,\"type\":\"short_answer\",\"user_answer_index\":\"nol\"},\"8\":{\"correct_answer_id\":[207,208,209],\"correct_answer_index\":[0,1,2],\"exp_gained\":10,\"feedback\":\"\\u003cp\\u003e\\u0026nbsp;Fungsi IsOrigin?, Jarak0, dan Absis digunakan dalam tipe POINT, sedangkan \\\"Penyebut\\\" digunakan dalam tipe pecahan.\\u0026nbsp;\\u003c/p\\u003e\",\"point_gained\":10,\"question_id\":85,\"type\":\"multiple_answer\",\"user_answer_id\":[208],\"user_answer_index\":[1],\"user_correct_answer_id\":[208]},\"9\":{\"correct_answer_index\":\"\\u003col\\u003e\\u003cli\\u003eKuadran ditentukan berdasarkan tanda nilai x dan y dari titik tersebut.\\u003c/li\\u003e\\u003c/ol\\u003e\\u003cp\\u003e\\u003cbr\\u003e\\u003c/p\\u003e\",\"exp_gained\":0,\"feedback\":\"\\u003cp\\u003eKuadran ditentukan berdasarkan tanda nilai x dan y dari titik tersebut:\\u003c/p\\u003e\\u003cul\\u003e\\u003cli\\u003eKuadran 1: x \\u0026gt; 0, y \\u0026gt; 0\\u003c/li\\u003e\\u003cli\\u003eKuadran 2: x \\u0026lt; 0, y \\u0026gt; 0\\u003c/li\\u003e\\u003cli\\u003eKuadran 3: x \\u0026lt; 0, y \\u0026lt; 0\\u003c/li\\u003e\\u003cli\\u003eKuadran 4: x \\u0026gt; 0, y \\u0026lt; 0\\u003c/li\\u003e\\u003c/ul\\u003e\\u003cp\\u003e\\u003cbr\\u003e\\u003c/p\\u003e\",\"point_gained\":0,\"question_id\":86,\"type\":\"essay\",\"user_answer_index\":\"Test essay\"}}',
